import itertools

def find_patterns(w):
    patterns = []
    # bits indexed by (row, col) with row=0,1; col=0..w-1
    # total bits: 2*w, so search space 2^(2w)
    for bits in range(1 << (2*w)):
        # build grid
        grid = [[ (bits >> (row*w + col)) & 1 for col in range(w)] for row in range(2)]
        ok=True
        # check all 2x3 rectangles: row always 0,1 (two rows)
        # col start index 0..w-1 (wrap-around for triples)
        for col in range(w):
            # sum of 6 cells in rows 0,1 and cols col, col+1, col+2 mod w
            s=0
            for r in range(2):
                for c in range(3):
                    s+=grid[r][(col+c)%w]
            if s!=2:
                ok=False
                break
        if ok:
            patterns.append(grid)
    return patterns

for w in range(1,7):
    pats = find_patterns(w)
    print(w, len(pats))

def verify_pattern(grid):
    # grid infinite periodic with given block rows and cols
    rows = len(grid)
    cols = len(grid[0])
    # check many positions
    for i in range(0, rows*2):
        for j in range(0, cols*3):
            s=0
            for di in range(2):
                for dj in range(3):
                    r = (i+di)%rows
                    c = (j+dj)%cols
                    s+=grid[r][c]
            if s!=2:
                return False
    return True

