# Let's generate patterns up to larger width and see counts
def count_patterns_up_to_width(max_width):
    from itertools import product
    patterns = []
    for bits in product([0,1], repeat=4):
        rows0 = [list(bits[:2]), list(bits[2:])]
        patterns.append(rows0)
    for w in range(2, max_width):
        new_patterns = []
        for pat in patterns:
            known_sum = pat[0][w-2] + pat[1][w-2] + pat[0][w-1] + pat[1][w-1]
            required_sum = 2 - known_sum
            if required_sum < 0 or required_sum > 2:
                continue
            if required_sum == 0:
                new_patterns.append([pat[0]+[0], pat[1]+[0]])
            elif required_sum == 2:
                new_patterns.append([pat[0]+[1], pat[1]+[1]])
            else: # required_sum == 1
                new_patterns.append([pat[0]+[1], pat[1]+[0]])
                new_patterns.append([pat[0]+[0], pat[1]+[1]])
        patterns = new_patterns
    return patterns

for w in [7,8,9,10]:
    pats = count_patterns_up_to_width(w)
    print(w, len(pats))

def compute_density_at_width(w):
    pats = count_patterns_up_to_width(w)
    densities = set()
    for pat in pats:
        total = sum(sum(row) for row in pat)
        densities.add(total/(2*w))
    return densities

