def count_paths_dp(target_x, target_y):
    # DP table where dp[x][y] = number of ways to reach (x,y)
    dp = [[0]*(target_y+1) for _ in range(target_x+1)]
    dp[0][0] = 1
    for x in range(target_x+1):
        for y in range(target_y+1):
            ways = dp[x][y]
            if ways == 0:
                continue
            # walk moves:
            # (x, y+1)
            if y+1 <= target_y:
                dp[x][y+1] += ways
            # (x+1, y)
            if x+1 <= target_x:
                dp[x+1][y] += ways
            # (x+1, y+1)
            if x+1 <= target_x and y+1 <= target_y:
                dp[x+1][y+1] += ways
            # jump moves:
            # (x, y+2)
            if y+2 <= target_y:
                dp[x][y+2] += ways
            # (x+2, y)
            if x+2 <= target_x:
                dp[x+2][y] += ways
            # (x+1, y+1) distinct
            if x+1 <= target_x and y+1 <= target_y:
                dp[x+1][y+1] += ways
    return dp[target_x][target_y]

