def count_ways(target_x, target_y):
    DP = [[0]*(target_y+1) for _ in range(target_x+1)]
    DP[0][0] = 1
    for x in range(target_x+1):
        for y in range(target_y+1):
            if x==0 and y==0:
                continue
            total = 0
            # walk up from (x,y-1)
            if y-1 >= 0:
                total += DP[x][y-1]
            # walk right from (x-1,y)
            if x-1 >= 0:
                total += DP[x-1][y]
            # walk diagonal from (x-1,y-1)
            if x-1>=0 and y-1>=0:
                total += DP[x-1][y-1]
            # jump up from (x,y-2)
            if y-2 >=0:
                total += DP[x][y-2]
            # jump right from (x-2,y)
            if x-2 >=0:
                total += DP[x-2][y]
            # jump diagonal from (x-1,y-1)
            if x-1>=0 and y-1>=0:
                total += DP[x-1][y-1]
            DP[x][y] = total
    return DP[target_x][target_y]

