def ways_to_target(n,m):
    # dp[x][y] for 0 <= x <= n, 0 <= y <= m
    dp = [[0]*(m+1) for _ in range(n+1)]
    dp[0][0] = 1
    for x in range(n+1):
        for y in range(m+1):
            if x==0 and y==0:
                continue
            total=0
            if x>=1:
                total+=dp[x-1][y]  # B
            if y>=1:
                total+=dp[x][y-1]  # A
            if x>=1 and y>=1:
                total+=2*dp[x-1][y-1]  # C+F
            if x>=2:
                total+=dp[x-2][y]  # E
            if y>=2:
                total+=dp[x][y-2]  # D
            dp[x][y]=total
    return dp[n][m], dp

