def partitions_of_n_into_k(n, k):
    result = []
    def helper(remaining, parts_left, max_val, current):
        if parts_left == 0:
            if remaining == 0:
                result.append(current[:])
            return
        # the next part can be at most max_val, at least 1
        # ensure we can fill remaining parts with at least 1 each
        for p in range(min(max_val, remaining - (parts_left-1)), 0, -1):
            # p must be >=1
            if remaining - p < (parts_left-1):
                continue
            current.append(p)
            helper(remaining - p, parts_left - 1, p, current)
            current.pop()
    helper(n, k, n, [])
    return result

parts = partitions_of_n_into_k(10, 5)
print(len(parts), parts)

def partitions_of_n_into_k(n, k, min_part=1):
    # generate partitions of n into exactly k parts, each >= min_part,
    # nonincreasing order (for uniqueness)
    if k == 0:
        if n == 0:
            yield []
        return
    if n < k * min_part:
        return
    # start with max possible first part
    for first in range(min(n - (k-1)*min_part), min_part-1, -1):
        for rest in partitions_of_n_into_k(n - first, k - 1, min_part):
            # ensure nonincreasing: first >= rest[0]
            if not rest or first >= rest[0]:
                yield [first] + rest

