        if n == 0:
            yield []
        return
    if n < k * min_part:
        return
    # choose first part value
    max_first = n - (k-1)*min_part
    for first in range(max_first, min_part-1, -1):
        for rest in partitions_of_n_into_k(n-first, k-1, min_part):
            # ensure nonincreasing order: first >= rest[0]
            if not rest or first >= rest[0]:
                yield [first] + rest

