def find_smallest():
    for n in range(1, 10000):
        if n % 25 == 0:
            # compute product of digits
            prod = 1
            digits = list(str(n))
            for d in digits:
                if d == '0':
                    prod = 0
                    break
                prod *= int(d)
            if prod > 0 and prod % 25 == 0:
                return n, prod, digits
    return None

