import itertools

def max_edges(A=20, B=10):
    max_val = 0
    best = None
    # generate all ways to partition A into k parts each >=1, with k between 2 and min(A, B) maybe up to B because each component needs at least one B.
    # Actually we can have at most B components because each component needs at least one B.
    # Let's iterate over k from 2 to B.
    # Partition A into k parts: each part >=1. That's integer compositions of A into k parts.
    # For each composition a_list, partition B into k parts: each part >=1. That's compositions of B into k parts.
    # Compute sum a_i*b_i, track max.
    from itertools import product, combinations_with_replacement

    max_val = -1
    best_parts = None

    # generate all integer compositions of n into k parts >=1.
    def compositions(n, k):
        # Using stars and bars: combinations of k-1 separators among n-1 positions.
        # More directly, use recursion.
        if k == 1:
            yield (n,)
        else:
            for i in range(1, n - k + 2):  # i at least 1, leaving n-i for k-1 parts at least 1 each: n-i >= k-1 => i <= n - (k-1)
                for rest in compositions(n - i, k - 1):
                    yield (i,) + rest

    for k in range(2, B+1):
        # generate compositions for A and B
        for a_parts in compositions(A, k):
            for b_parts in compositions(B, k):
                total = sum(ai*bi for ai, bi in zip(a_parts, b_parts))
                if total > max_val:
                    max_val = total
                    best_parts = (k, a_parts, b_parts)
    return max_val, best_parts

