def smallest_permutation(num):
    s = str(num)
    digits = list(s)
    # sort digits
    digits_sorted = sorted(digits)
    # If the smallest digit is '0', we need the first non-zero digit to be first.
    if digits_sorted[0] == '0':
        # find first non-zero
        for i, d in enumerate(digits_sorted):
            if d != '0':
                # swap
                digits_sorted[0], digits_sorted[i] = digits_sorted[i], digits_sorted[0]
                break
    # join
    return int(''.join(digits_sorted))

def find_next_year(start=2009):
    y = start + 1
    while True:
        if smallest_permutation(y) == y:
            return y
        y += 1

print(find_next_year())

def next_property_year(start):
    year = start + 1
    while year <= 9999:
        if has_property(year):
            return year
        year += 1
    return None

next_year = next_property_year(2009)
print(next_year)

def min_permutation(num):
    s = str(num)
    # Ensure it's a four-digit number
    if len(s)!=4:
        return None
    # Minimum permutation without leading zero
    mins = None
    import itertools
    for perm in set(itertools.permutations(s)):
        if perm[0]=='0':
            continue
        val = int(''.join(perm))
        if mins is None or val < mins:
            mins = val
    return mins

def first_repeat_after(start=2009):
    for year in range(start+1, 10000):
        if year < 1000:  # skip non four-digit
            continue
        if min_permutation(year) == year:
            return year
    return None

print(first_repeat_after())

solutions = []
for a in range(-200, 201):
    for b in range(-200, 401):
        d12 = 12*a + b
        d13 = 13*a + b
        d15 = 15*a + b
        if not (81.5 <= d12 < 82.5):
            continue
        if not (45.5 <= d15 < 46.5):
            continue
        if not (70.5 <= d13 < 71.5) and not (abs(d13 - 71.5) < 1e-9):
            continue
        # all constraints satisfied
        d16 = 16*a + b
        solutions.append((a,b,d12,d13,d15,d16))
print(len(solutions))

from fractions import Fraction

def find_solutions(max_denom=10):
    sols=set()
    for d in range(1, max_denom+1):
        # p in some range, say -200*d to 200*d
        for p in range(-200*d, 200*d+1):
            a = Fraction(p, d)
            # b we compute from each d16 candidate? Instead loop over possible b rational with same denominator?
            # Let's also loop over r for b = Fraction(r, d)
            for r in range(-200*d, 200*d+1):
                b = Fraction(r, d)
                d12 = 12*a + b
                d13 = 13*a + b
                d15 = 15*a + b
                if not (Fraction(81,2) <= d12 < Fraction(83,2)):
                    continue
                if not (Fraction(45,2) <= d15 < Fraction(47,2)):
                    continue
                # d13 rounds to 71: normally [70.5,71.5)
                if not (Fraction(70,2) <= d13 < Fraction(71,2)) and not (d13 == Fraction(71,2)):
                    continue
                d16 = 16*a + b
                sols.add(d16)
    return sorted(sols)

possible_D16 = find_solutions(10)
print(possible_D16[:20], len(possible_D16))

def find_feasible_grid(step_d=1e-4, step_v=1e-4):
    d_vals = np.arange(81.5, 82.5+step_d, step_d)
    v_vals = np.arange(11.5, 12.5+step_v, step_v)
    feas = []
    for d0 in d_vals:
        for v in v_vals:
            if (70.5 - 1e-9 <= d0 - v <= 71.5 + 1e-9) and (45.5 - 1e-9 <= d0 - 3*v <= 46.5 + 1e-9):
                feas.append((d0, v))
    return feas

feas_grid = find_feasible_grid(step_d=0.001, step_v=0.001)
print(len(feas_grid))

from fractions import Fraction
import math

def find_feasible_solutions(k):
    sol = []
    for q in range(1,201):
        p_min = math.ceil(81.5 * q)
        p_max = math.floor(82.5 * q)
        for p in range(p_min, p_max + 1):
            d0 = Fraction(p, q)
            lhs = (3*d0 + k) / 4
            if not (Fraction(141, 2) <= lhs <= Fraction(143, 2)):
                continue
            rhs = (d0 + 3*k) / 4
            if not (Fraction(91, 2) <= rhs <= Fraction(93, 2)):
                continue
            v = (d0 - k) / 4
            if v <= 0:
                continue
            sol.append((d0, v))
    return sol

for k in [34, 35]:
    sols = find_feasible_solutions(k)
    print(k, len(sols))
    if sols:
        print(sols[:5])

# Let's search over a wider range of integer k, say from 0 to 100.
solutions_by_k = {}
for k in range(0, 101):
    sols = find_feasible_solutions(k)
    if sols:
        solutions_by_k[k] = sols[:10]  # store up to 10 examples

print(solutions_by_k)

def feasible_intervals(a):
    # given a, return interval of v that satisfies both constraints
    low1 = a - 71.5
    high1 = a - 70.5
    low2 = (a - 46.5)/3
    high2 = (a - 45.5)/3
    low = max(low1, low2)
    high = min(high1, high2)
    if low <= high:
        return (low, high)
    else:
        return None

# evaluate for many a values
vals = []
for a in np.linspace(81.5, 82.5, 1001):
    iv = feasible_intervals(a)
    if iv:
        vals.append((a, iv))
print(len(vals))

# Let's verify if any other values of a slightly beyond 82.5 could give intersection but a must be in [81.5,82.5]
def intersection_interval(a):
    low1 = a - 71.5
    high1 = a - 70.5
    low2 = (a - 46.5)/3
    high2 = (a - 45.5)/3
    return max(low1, low2), min(high1, high2)

for a_test in [82.4, 82.49, 82.499]:
    low, high = intersection_interval(a_test)
    print(a_test, low, high, low <= high)

\[
\begin{aligned}
\sum_{k=1}^{20}\log_{5^{k}}3^{k^{2}}
&=\sum_{k=1}^{20}\frac{k^{2}\ln3}{k\ln5}
 =\sum_{k=1}^{20}k\frac{\ln3}{\ln5}
 =\log_{5}3\sum_{k=1}^{20}k
 =\log_{5}3\cdot\frac{20\cdot21}{2}
 =210\,\log_{5}3,\\[4pt]
\sum_{k=1}^{100}\log_{9^{k}}25^{k}
&=\sum_{k=1}^{100}\frac{k\ln25}{k\ln9}
 =\frac{\ln25}{\ln9}
 =\log_{9}25
 =\log_{3^{2}}5^{2}
 =\log_{3}5.
\end{aligned}
\]

Thus the second sum equals \(100\,\log_{9}25 = 100\,\log_{3}5\).

The product is

\[
\bigl(210\,\log_{5}3\bigr)\bigl(100\,\log_{3}5\bigr)
=21000\;(\log_{5}3\cdot\log_{3}5).
\]

Since \(\log_{a}b\cdot\log_{b}a=1\),

\[
\log_{5}3\cdot\log_{3}5 = 1.
\]

Hence the whole expression equals

\[
21000\cdot 1 = \boxed{21000}.
\]

