# Let's search primes p > 34 up to say 200
for p in sp.primerange(35,200):
    x = 5*p - 170
    if x <= 0:
        continue
    # Compute median
    numbers = [24,27,55,64,x]
    numbers_sorted = sorted(numbers)
    median = numbers_sorted[2]  # zero-indexed third element
    # median multiple of 3?
    if median % 3 != 0:
        continue
    # Mean prime?
    mean = (24+27+55+64+x)/5
    if mean != int(mean):
        continue
    if not is_prime(int(mean)):
        continue
    possible.append((p, x, median, mean))
print(possible[:20], len(possible))

