def is_prime(n):
    if n<2:
        return False
    if n%2==0:
        return n==2
    r=int(n**0.5)
    for i in range(3,r+1,2):
        if n%i==0:
            return False
    return True

primes = {x: is_prime((170+x)//5) for x in candidates}
print(primes)

