def is_spacy(subset, n=15):
    # subset is a set of integers
    for i in range(1, n-1):
        triple = {i,i+1,i+2}
        if len(subset & triple) > 1:
            return False
    return True

def spacy_subsets(n):
    from itertools import combinations
    res = []
    all_elements = list(range(1,n+1))
    for r in range(n+1):
        for comb in combinations(all_elements, r):
            if is_spacy(set(comb), n):
                res.append(set(comb))
    return res

def count_spacy(n):
    return len(spacy_subsets(n))

# compute a_n for n=0..10 manually via brute
counts = [count_spacy(i) for i in range(0,11)]
